data class TaskListUiState(
    val items: List<Task> = emptyList(),
    val isLoading: Boolean = false,
    val errorMessage: String? = null,
)

class TaskListViewModel(
    repository: TaskRepository,
) : ViewModel() {
    val state = repository.observeTasks()
        .map { tasks -> TaskListUiState(items = tasks) }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5_000),
            initialValue = TaskListUiState(isLoading = true),
        )
}

actor ImageCache {
    private var images: [URL: Data] = [:]

    func value(for url: URL) -> Data? {
        images[url]
    }

    func insert(_ data: Data, for url: URL) {
        images[url] = data
    }
}

func loadImage(from url: URL, cache: ImageCache) async throws -> Data {
    if let cached = await cache.value(for: url) {
        return cached
    }

    let (data, _) = try await URLSession.shared.data(from: url)
    try Task.checkCancellation()
    await cache.insert(data, for: url)
    return data
}

def two_sum(nums: list[int], target: int) -> tuple[int, int] | None:
    seen: dict[int, int] = {}

    for index, value in enumerate(nums):
        complement = target - value
        if complement in seen:
            return seen[complement], index
        seen[value] = index

    return None

fn first_word(text: &str) -> &str {
    match text.as_bytes().iter().position(|byte| *byte == b' ') {
        Some(index) => &text[..index],
        None => text,
    }
}

fn main() {
    let line = String::from("ownership made visible");
    let word = first_word(&line);
    println!("{word}");
}

